module shift_register(
    input        rst,
    input        reset,
    input        load,
    input [15:0] load_data,
    input        shift_enable,
    output reg [15:0] q
);

always @(posedge rst or posedge reset)
begin
    if (reset)
        q <= 16'b0;
    else if (load)
        q <= load_data;
    else if (shift_enable)
        q <= {q[14:0], 1'b0};
end

endmodule
